   542→dictIterator *dictGetIterator(dict *d)
   543→{
   544→    dictIterator *iter = zmalloc(sizeof(*iter));
   545→
   546→    iter->d = d;
   547→    iter->table = 0;
   548→    iter->index = -1;
   549→    iter->safe = 0;
   550→    iter->entry = NULL;
   551→    iter->nextEntry = NULL;
   552→    return iter;
   553→}
