   766→/* Function to reverse bits. Algorithm from:
   767→ * http://graphics.stanford.edu/~seander/bithacks.html#ReverseParallel */
   768→static unsigned long rev(unsigned long v) {
   769→    unsigned long s = 8 * sizeof(v); // bit size; must be power of 2
   770→    unsigned long mask = ~0;
   771→    while ((s >>= 1) > 0) {
   772→        mask ^= (mask << s);
   773→        v = ((v >> s) & mask) | ((v << s) & ~mask);
   774→    }
   775→    return v;
   776→}
   777→
   778→/* dictScan() is used to iterate over the elements of a dictionary.
   779→ *
   780→ * Iterating works the following way:
   781→ *
   782→ * 1) Initially you call the function using a cursor (v) value of 0.
   783→ * 2) The function performs one step of the iteration, and returns the
   784→ *    new cursor value you must use in the next call.
   785→ * 3) When the returned cursor is 0, the iteration is complete.
   786→ *
   787→ * The function guarantees all elements present in the
   788→ * dictionary get returned between the start and end of the iteration.
   789→ * However it is possible some elements get returned multiple times.
   790→ *
   791→ * For every element returned, the callback argument 'fn' is
   792→ * called with 'privdata' as first argument and the dictionary entry
   793→ * 'de' as second argument.
   794→ *
   795→ * HOW IT WORKS.
   796→ *
   797→ * The iteration algorithm was designed by Pieter Noordhuis.
   798→ * The main idea is to increment a cursor starting from the higher order
   799→ * bits. That is, instead of incrementing the cursor normally, the bits
   800→ * of the cursor are reversed, then the cursor is incremented, and finally
   801→ * the bits are reversed again.
   802→ *
   803→ * This strategy is needed because the hash table may be resized between
   804→ * iteration calls.
   805→ *
   806→ * dict.c hash tables are always power of two in size, and they
   807→ * use chaining, so the position of an element in a given table is given
   808→ * by computing the bitwise AND between Hash(key) and SIZE-1
   809→ * (where SIZE-1 is always the mask that is equivalent to taking the rest
   810→ *  of the division between the Hash of the key and SIZE).
   811→ *
   812→ * For example if the current hash table size is 16, the mask is
   813→ * (in binary) 1111. The position of a key in the hash table will always be
   814→ * the last four bits of the hash output, and so forth.
   815→ *
   816→ * WHAT HAPPENS IF THE TABLE CHANGES IN SIZE?
   817→ *
   818→ * If the hash table grows, elements can go anywhere in one multiple of
   819→ * the old bucket: for example let's say we already iterated with
   820→ * a 4 bit cursor 1100 (the mask is 1111 because hash table size = 16).
   821→ *
   822→ * If the hash table will be resized to 64 elements, then the new mask will
   823→ * be 111111. The new buckets you obtain by substituting in ??1100
   824→ * with either 0 or 1 can be targeted only by keys we already visited
   825→ * when scanning the bucket 1100 in the smaller hash table.
   826→ *
   827→ * By iterating the higher bits first, because of the inverted counter, the
   828→ * cursor does not need to restart if the table size gets bigger. It will
   829→ * continue iterating using cursors without '1100' at the end, and also
   830→ * without any other combination of the final 4 bits already explored.
   831→ *
   832→ * Similarly when the table size shrinks over time, for example going from
   833→ * 16 to 8, if a combination of the lower three bits (the mask for size 8
   834→ * is 111) were already completely explored, it would not be visited again
   835→ * because we are sure we tried, for example, both 0111 and 1111 (all the
   836→ * variations of the higher bit) so we don't need to test it again.
   837→ *
   838→ * WAIT... YOU HAVE *TWO* TABLES DURING REHASHING!
   839→ *
   840→ * Yes, this is true, but we always iterate the smaller table first, then
   841→ * we test all the expansions of the current cursor into the larger
   842→ * table. For example if the current cursor is 101 and we also have a
   843→ * larger table of size 16, we also test (0)101 and (1)101 inside the larger
   844→ * table. This reduces the problem back to having only one table, where
   845→ * the larger one, if it exists, is just an expansion of the smaller one.
   846→ *
   847→ * LIMITATIONS
   848→ *
   849→ * This iterator is completely stateless, and this is a huge advantage,
   850→ * including no additional memory used.
   851→ *
   852→ * The disadvantages resulting from this design are:
   853→ *
   854→ * 1) It is possible we return elements more than once. However this is usually
   855→ *    easy to deal with in the application level.
   856→ * 2) The iterator must return multiple elements per call, as it needs to always
   857→ *    return all the keys chained in a given bucket, and all the expansions, so
   858→ *    we are sure we don't miss keys moving during rehashing.
   859→ * 3) The reverse cursor is somewhat hard to understand at first, but this
   860→ *    comment is supposed to help.
   861→ */
   862→unsigned long dictScan(dict *d,
   863→                       unsigned long v,
   864→                       dictScanFunction *fn,
   865→                       dictScanBucketFunction* bucketfn,
   866→                       void *privdata)
   867→{
   868→    dictht *t0, *t1;
   869→    const dictEntry *de, *next;
   870→    unsigned long m0, m1;
   871→
   872→    if (dictSize(d) == 0) return 0;
   873→
   874→    if (!dictIsRehashing(d)) {
   875→        t0 = &(d->ht[0]);
   876→        m0 = t0->sizemask;
   877→
   878→        /* Emit entries at cursor */
   879→        if (bucketfn) bucketfn(privdata, &t0->table[v & m0]);
   880→        de = t0->table[v & m0];
   881→        while (de) {
   882→            next = de->next;
   883→            fn(privdata, de);
   884→            de = next;
   885→        }
   886→
   887→        /* Set unmasked bits so incrementing the reversed cursor
   888→         * operates on the masked bits */
   889→        v |= ~m0;
   890→
   891→        /* Increment the reverse cursor */
   892→        v = rev(v);
   893→        v++;
   894→        v = rev(v);
   895→
   896→    } else {
   897→        t0 = &d->ht[0];
   898→        t1 = &d->ht[1];
   899→
   900→        /* Make sure t0 is the smaller and t1 is the bigger table */
   901→        if (t0->size > t1->size) {
   902→            t0 = &d->ht[1];
   903→            t1 = &d->ht[0];
   904→        }
   905→
   906→        m0 = t0->sizemask;
   907→        m1 = t1->sizemask;
   908→
   909→        /* Emit entries at cursor */
   910→        if (bucketfn) bucketfn(privdata, &t0->table[v & m0]);
   911→        de = t0->table[v & m0];
   912→        while (de) {
   913→            next = de->next;
   914→            fn(privdata, de);
   915→            de = next;
   916→        }
   917→
   918→        /* Iterate over indices in larger table that are the expansion
   919→         * of the index pointed to by the cursor in the smaller table */
   920→        do {
   921→            /* Emit entries at cursor */
   922→            if (bucketfn) bucketfn(privdata, &t1->table[v & m1]);
   923→            de = t1->table[v & m1];
   924→            while (de) {
   925→                next = de->next;
   926→                fn(privdata, de);
   927→                de = next;
   928→            }
   929→
   930→            /* Increment the reverse cursor not covered by the smaller mask.*/
   931→            v |= ~m1;
   932→            v = rev(v);
   933→            v++;
   934→            v = rev(v);
   935→
   936→            /* Continue while bits covered by mask difference is non-zero */
   937→        } while (v & (m0 ^ m1));
   938→    }
   939→
   940→    return v;
   941→}
