   944→
   945→/* Expand the hash table if needed */
   946→static int _dictExpandIfNeeded(dict *d)
   947→{
   948→    /* Incremental rehashing already in progress. Return. */
   949→    if (dictIsRehashing(d)) return DICT_OK;
   950→
   951→    /* If the hash table is empty expand it to the initial size. */
   952→    if (d->ht[0].size == 0) return dictExpand(d, DICT_HT_INITIAL_SIZE);
   953→
   954→    /* If we reached the 1:1 ratio, and we are allowed to resize the hash
   955→     * table (global setting) or we should avoid it but the ratio between
   956→     * elements/buckets is over the "safe" threshold, we resize doubling
   957→     * the number of buckets. */
   958→    if (d->ht[0].used >= d->ht[0].size &&
   959→        (dict_can_resize ||
   960→         d->ht[0].used/d->ht[0].size > dict_force_resize_ratio))
   961→    {
   962→        return dictExpand(d, d->ht[0].used*2);
   963→    }
   964→    return DICT_OK;
   965→}
   966→
   967→/* Our hash table capability is a power of two */
   968→static unsigned long _dictNextPower(unsigned long size)
   969→{
   970→    unsigned long i = DICT_HT_INITIAL_SIZE;
   971→
   972→    if (size >= LONG_MAX) return LONG_MAX + 1LU;
   973→    while(1) {
   974→        if (i >= size)
   975→            return i;
   976→        i *= 2;
   977→    }
   978→}
   979→
   980→/* Returns the index of a free slot that can be populated with
   981→ * a hash entry for the given 'key'.
   982→ * If the key already exists, -1 is returned
   983→ * and the optional output parameter may be filled.
   984→ *
   985→ * Note that if we are in the process of rehashing the hash table, the
   986→ * index is always returned in the context of the second (new) hash table. */
   987→static long _dictKeyIndex(dict *d, const void *key, uint64_t hash, dictEntry **existing)
   988→{
   989→    unsigned long idx, table;
   990→    dictEntry *he;
   991→    if (existing) *existing = NULL;
   992→
   993→    /* Expand the hash table if needed */
   994→    if (_dictExpandIfNeeded(d) == DICT_ERR)
   995→        return -1;
   996→    for (table = 0; table <= 1; table++) {
   997→        idx = hash & d->ht[table].sizemask;
   998→        /* Search if this slot does not already contain the given key */
   999→        he = d->ht[table].table[idx];
  1000→        while(he) {
  1001→            if (key==he->key || dictCompareKeys(d, key, he->key)) {
  1002→                if (existing) *existing = he;
  1003→                return -1;
  1004→            }
  1005→            he = he->next;
  1006→        }
  1007→        if (!dictIsRehashing(d)) break;
  1008→    }
  1009→    return idx;
  1010→}
