  1012→void dictEmpty(dict *d, void(callback)(void*)) {
  1013→    _dictClear(d,&d->ht[0],callback);
  1014→    _dictClear(d,&d->ht[1],callback);
  1015→    d->rehashidx = -1;
  1016→    d->iterators = 0;
  1017→}
