  1020→    dict_can_resize = 1;
  1021→}
  1022→
  1023→void dictDisableResize(void) {
  1024→    dict_can_resize = 0;
  1025→}
  1026→
  1027→uint64_t dictGetHash(dict *d, const void *key) {
  1028→    return dictHashKey(d, key);
  1029→}
  1030→
  1031→/* Finds the dictEntry reference by using pointer and pre-calculated hash.
  1032→ * oldkey is a dead pointer and should not be accessed.
  1033→ * the hash value should be provided using dictGetHash.
  1034→ * no string / key comparison is performed.
  1035→ * return value is the reference to the dictEntry if found, or NULL if not found. */
  1036→dictEntry **dictFindEntryRefByPtrAndHash(dict *d, const void *oldptr, uint64_t hash) {
  1037→    dictEntry *he, **heref;
  1038→    unsigned long idx, table;
  1039→
  1040→    if (d->ht[0].used + d->ht[1].used == 0) return NULL; /* dict is empty */
  1041→    for (table = 0; table <= 1; table++) {
  1042→        idx = hash & d->ht[table].sizemask;
  1043→        heref = &d->ht[table].table[idx];
  1044→        he = *heref;
  1045→        while(he) {
  1046→            if (oldptr==he->key)
  1047→                return heref;
  1048→            heref = &he->next;
  1049→            he = *heref;
  1050→        }
  1051→        if (!dictIsRehashing(d)) return NULL;
  1052→    }
  1053→    return NULL;
  1054→}
  1055→
  1056→/* ------------------------------- Debugging ---------------------------------*/
  1057→
  1058→#define DICT_STATS_VECTLEN 50
  1059→size_t _dictGetStatsHt(char *buf, size_t bufsize, dictht *ht, int tableid) {
  1060→    unsigned long i, slots = 0, chainlen, maxchainlen = 0;
  1061→    unsigned long totchainlen = 0;
  1062→    unsigned long clvector[DICT_STATS_VECTLEN];
  1063→    size_t l = 0;
  1064→
  1065→    if (ht->used == 0) {
  1066→        return snprintf(buf,bufsize,
  1067→            "No stats available for empty dictionaries\n");
  1068→    }
  1069→
  1070→    /* Compute stats. */
  1071→    for (i = 0; i < DICT_STATS_VECTLEN; i++) clvector[i] = 0;
  1072→    for (i = 0; i < ht->size; i++) {
  1073→        dictEntry *he;
  1074→
  1075→        if (ht->table[i] == NULL) {
  1076→            clvector[0]++;
  1077→            continue;
  1078→        }
  1079→        slots++;
  1080→        /* For each hash entry on this slot... */
  1081→        chainlen = 0;
  1082→        he = ht->table[i];
  1083→        while(he) {
  1084→            chainlen++;
  1085→            he = he->next;
  1086→        }
  1087→        clvector[(chainlen < DICT_STATS_VECTLEN) ? chainlen : (DICT_STATS_VECTLEN-1)]++;
  1088→        if (chainlen > maxchainlen) maxchainlen = chainlen;
  1089→        totchainlen += chainlen;
  1090→    }
  1091→
  1092→    /* Generate human readable stats. */
  1093→    l += snprintf(buf+l,bufsize-l,
  1094→        "Hash table %d stats (%s):\n"
  1095→        " table size: %ld\n"
  1096→        " number of elements: %ld\n"
  1097→        " different slots: %ld\n"
  1098→        " max chain length: %ld\n"
  1099→        " avg chain length (counted): %.02f\n"
  1100→        " avg chain length (computed): %.02f\n"
  1101→        " Chain length distribution:\n",
  1102→        tableid, (tableid == 0) ? "main hash table" : "rehashing target",
  1103→        ht->size, ht->used, slots, maxchainlen,
  1104→        (float)totchainlen/slots, (float)ht->used/slots);
  1105→
  1106→    for (i = 0; i < DICT_STATS_VECTLEN-1; i++) {
  1107→        if (clvector[i] == 0) continue;
  1108→        if (l >= bufsize) break;
  1109→        l += snprintf(buf+l,bufsize-l,
  1110→            "   %s%ld: %ld (%.02f%%)\n",
  1111→            (i == DICT_STATS_VECTLEN-1)?">= ":"",
  1112→            i, clvector[i], ((float)clvector[i]/ht->size)*100);
  1113→    }
  1114→
  1115→    /* Unlike snprintf(), teturn the number of characters actually written. */
  1116→    if (bufsize) buf[bufsize-1] = '\0';
  1117→    return strlen(buf);
  1118→}
  1119→
  1120→void dictGetStats(char *buf, size_t bufsize, dict *d) {
  1121→    size_t l;
  1122→    char *orig_buf = buf;
  1123→    size_t orig_bufsize = bufsize;
  1124→
  1125→    l = _dictGetStatsHt(buf,bufsize,&d->ht[0],0);
  1126→    buf += l;
  1127→    bufsize -= l;
  1128→    if (dictIsRehashing(d) && bufsize > 0) {
  1129→        _dictGetStatsHt(buf,bufsize,&d->ht[1],1);
  1130→    }
  1131→    /* Make sure there is a NULL term at the end. */
  1132→    if (orig_bufsize) orig_buf[orig_bufsize-1] = '\0';
  1133→}
  1134→
  1135→/* ------------------------------- Benchmark ---------------------------------*/
  1136→
  1137→#ifdef DICT_BENCHMARK_MAIN
  1138→
  1139→#include "sds.h"
  1140→
  1141→uint64_t hashCallback(const void *key) {
  1142→    return dictGenHashFunction((unsigned char*)key, sdslen((char*)key));
  1143→}
  1144→
  1145→int compareCallback(void *privdata, const void *key1, const void *key2) {
  1146→    int l1,l2;
  1147→    DICT_NOTUSED(privdata);
  1148→
  1149→    l1 = sdslen((sds)key1);
  1150→    l2 = sdslen((sds)key2);
  1151→    if (l1 != l2) return 0;
  1152→    return memcmp(key1, key2, l1) == 0;
  1153→}
  1154→
  1155→void freeCallback(void *privdata, void *val) {
  1156→    DICT_NOTUSED(privdata);
  1157→
  1158→    sdsfree(val);
  1159→}
  1160→
  1161→dictType BenchmarkDictType = {
  1162→    hashCallback,
  1163→    NULL,
  1164→    NULL,
  1165→    compareCallback,
  1166→    freeCallback,
  1167→    NULL
  1168→};
  1169→
  1170→#define start_benchmark() start = timeInMilliseconds()
  1171→#define end_benchmark(msg) do { \
  1172→    elapsed = timeInMilliseconds()-start; \
  1173→    printf(msg ": %ld items in %lld ms\n", count, elapsed); \
  1174→} while(0);
  1175→
  1176→/* dict-benchmark [count] */
  1177→int main(int argc, char **argv) {
  1178→    long j;
  1179→    long long start, elapsed;
  1180→    dict *dict = dictCreate(&BenchmarkDictType,NULL);
  1181→    long count = 0;
  1182→
  1183→    if (argc == 2) {
  1184→        count = strtol(argv[1],NULL,10);
  1185→    } else {
  1186→        count = 5000000;
  1187→    }
  1188→
  1189→    start_benchmark();
  1190→    for (j = 0; j < count; j++) {
  1191→        int retval = dictAdd(dict,sdsfromlonglong(j),(void*)j);
  1192→        assert(retval == DICT_OK);
  1193→    }
  1194→    end_benchmark("Inserting");
  1195→    assert((long)dictSize(dict) == count);
  1196→
  1197→    /* Wait for rehashing. */
  1198→    while (dictIsRehashing(dict)) {
  1199→        dictRehashMilliseconds(dict,100);
  1200→    }
  1201→
  1202→    start_benchmark();
  1203→    for (j = 0; j < count; j++) {
  1204→        sds key = sdsfromlonglong(j);
  1205→        dictEntry *de = dictFind(dict,key);
  1206→        assert(de != NULL);
  1207→        sdsfree(key);
  1208→    }
  1209→    end_benchmark("Linear access of existing elements");
  1210→
  1211→    start_benchmark();
  1212→    for (j = 0; j < count; j++) {
  1213→        sds key = sdsfromlonglong(j);
  1214→        dictEntry *de = dictFind(dict,key);
  1215→        assert(de != NULL);
  1216→        sdsfree(key);
  1217→    }
  1218→    end_benchmark("Linear access of existing elements (2nd round)");
  1219→
  1220→    start_benchmark();
  1221→    for (j = 0; j < count; j++) {
  1222→        sds key = sdsfromlonglong(rand() % count);
  1223→        dictEntry *de = dictFind(dict,key);
  1224→        assert(de != NULL);
  1225→        sdsfree(key);
  1226→    }
  1227→    end_benchmark("Random access of existing elements");
  1228→
  1229→    start_benchmark();
  1230→    for (j = 0; j < count; j++) {
  1231→        sds key = sdsfromlonglong(rand() % count);
  1232→        key[0] = 'X';
  1233→        dictEntry *de = dictFind(dict,key);
  1234→        assert(de == NULL);
  1235→        sdsfree(key);
  1236→    }
  1237→    end_benchmark("Accessing missing");
  1238→
  1239→    start_benchmark();
  1240→    for (j = 0; j < count; j++) {
  1241→        sds key = sdsfromlonglong(j);
  1242→        int retval = dictDelete(dict,key);
  1243→        assert(retval == DICT_OK);
  1244→        key[0] += 17; /* Change first number to letter. */
  1245→        retval = dictAdd(dict,key,(void*)j);
  1246→        assert(retval == DICT_OK);
  1247→    }
  1248→    end_benchmark("Removing and adding");
  1249→}
